SELECT COUNT(*) FROM vendor WHERE vendor_usage = 'Y'
and vendor_type = #{searchType}
and ( upper(vendor_name) like trim(upper('%' || #{searchKeyword} || '%')) or upper(vendor_id) like trim(upper('%' || #{searchKeyword} || '%')) )

SELECT * FROM ( SELECT ROWNUM RN, V.* FROM ( SELECT vendor_id AS vendorId, vendor_name AS vendorName, vendor_type AS vendorType, vendor_tel AS vendorTel, vendor_email AS vendorEmail, vendor_zipcode AS vendorZipcode, vendor_addr AS vendorAddr, vendor_addr_detail AS vendorAddrDetail, vendor_usage AS vendorUsage FROM vendor WHERE vendor_usage = 'Y'
and vendor_type = #{vendorDTO.searchType}
and ( upper(vendor_name) like trim(upper('%' || #{vendorDTO.searchKeyword} || '%')) or upper(vendor_id) like trim(upper('%' || #{vendorDTO.searchKeyword} || '%')) )
ORDER BY vendor_id DESC ) V ) WHERE RN BETWEEN #{page.startRow} AND #{page.endRow}

mapper.update:

UPDATE vendor
SET vendor_usage = 'N'
WHERE vendor_id = #{vendorId}
